161	impl<T> Pointable for T {
162	    const ALIGN: usize = mem::align_of::<T>();
163	
164	    type Init = T;
165	
166	    unsafe fn init(init: Self::Init) -> *mut () {
167	        Box::into_raw(Box::new(init)).cast::<()>()
168	    }
169	
170	    unsafe fn as_ptr(ptr: *mut ()) -> *const Self {
171	        ptr as *const T
172	    }
173	
174	    unsafe fn as_mut_ptr(ptr: *mut ()) -> *mut Self {
175	        ptr.cast::<T>()
176	    }
177	
178	    unsafe fn drop(ptr: *mut ()) {
179	        drop(unsafe { Box::from_raw(ptr.cast::<T>()) });
