209	impl<T> Array<T> {
210	    fn layout(len: usize) -> Layout {
211	        Layout::new::<Self>()
212	            .extend(Layout::array::<MaybeUninit<T>>(len).unwrap())
213	            .unwrap()
214	            .0
215	            .pad_to_align()
216	    }
217	}
